"""Library Forge

Build a tiny math library both ways -- as a static archive (libmathx.a) and as a shared object (libmathx.so) -- link an app against each, and see the loader error that dynamic linking can produce when LD_LIBRARY_PATH is not set. The launcher rebuilds your Makefile targets and checks both binaries itself.
"""
import os, shutil, subprocess, sys, tempfile, zipfile

# -- Crypto / obfuscation --
import hashlib as _hl, hmac as _hm

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000
_BLOB      = "b7b37cdbce3798ae935dc83919fb55ed7adeda8418811c9e76fc12715aee1ee371be8135180717e9cb0fa4151867724f1fb4ac7afe507bdb9cc3d7"

def _decrypt(key_str):
    key  = _hl.pbkdf2_hmac("sha256", key_str.encode(), _SALT, _KDF_ITERS)
    blob = bytes.fromhex(_BLOB)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    ks, i, stream = b"", 0, b""
    while len(stream) < len(ct):
        stream += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return bytes(a ^ b for a, b in zip(ct, stream)).decode()

# -- Helpers --
import difflib as _difflib
import random as _random
import textwrap as _tw

_LINE_WIDTH = 70


def _norm_answer(s):
    # Fold away the differences that should not matter when matching a typed
    # answer against an option: surrounding whitespace, internal run-length,
    # letter case, and a trailing period.
    return " ".join(s.strip().lower().split()).strip(" .")


def _best_match(raw, options, cutoff=0.82):
    # Resolve a typed answer to one of `options`, forgiving tiny typos. Returns
    # the exact option string (so the caller can decrypt with the canonical
    # value), or None if nothing is close enough.
    norm = {}
    for opt in options:
        norm.setdefault(_norm_answer(opt), opt)
    key = _norm_answer(raw)
    if key in norm:
        return norm[key]
    close = _difflib.get_close_matches(key, list(norm.keys()), n=1, cutoff=cutoff)
    return norm[close[0]] if close else None


def _show_choices(options):
    print("  Choose one (type or paste the exact phrase -- small typos are ok):")
    for opt in options:
        for ln in _tw.wrap(opt, width=_LINE_WIDTH - 6,
                           initial_indent="    - ", subsequent_indent="      "):
            print(ln)

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _wrap(text):
    return _tw.wrap(text, width=_LINE_WIDTH - 4,
                    initial_indent="  ", subsequent_indent="    ")

def _show_wrong(raw, wrong_dict):
    exp = wrong_dict.get(raw)
    if exp:
        print()
        for ln in _wrap(f"[wrong] {exp}"):
            print(ln)
    else:
        print(f"  [wrong] {raw!r} is not the correct answer.")

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()

def die(msg):
    print(f"error: {msg}", file=sys.stderr)
    sys.exit(1)

def _compile_run(src, name, repo_dir):
    binary = os.path.join(repo_dir, name)
    r = subprocess.run(
        ["g++", "-std=c++17", "-o", binary, os.path.join(repo_dir, src)],
        capture_output=True, text=True,
    )
    if r.returncode != 0:
        return None, r.stderr
    try:
        run = subprocess.run([binary], capture_output=True, text=True, timeout=10)
    except subprocess.TimeoutExpired:
        return None, "timeout"
    return run.stdout.strip(), None

def _make_build(repo_dir):
    r = subprocess.run(["make"], capture_output=True, text=True, cwd=repo_dir)
    return r.returncode == 0, r.stderr

def _run_binary(repo_dir, name, timeout=10):
    exe = os.path.join(repo_dir, name)
    if not os.path.isfile(exe):
        return None, f"{name} binary not found -- did the build succeed?"
    try:
        r = subprocess.run([exe], capture_output=True, text=True, timeout=timeout, cwd=repo_dir)
        return r.stdout.strip(), None
    except subprocess.TimeoutExpired:
        return None, "timeout"
    except Exception as e:
        return None, str(e)

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ZIP   = os.path.join(SCRIPT_DIR, "repo.zip")

def _extract_repo():
    if not os.path.isfile(REPO_ZIP):
        die("repo.zip not found.")
    work_dir = tempfile.mkdtemp(prefix="library-forge-")
    with zipfile.ZipFile(REPO_ZIP, "r") as zf:
        zf.extractall(work_dir)
        # zipfile.extractall() does not restore Unix permission bits, so any
        # script shipped in the zip (e.g. lint.sh) loses its executable bit
        # here. Restore the mode recorded in the archive for each file.
        for info in zf.infolist():
            mode = info.external_attr >> 16
            if mode:
                os.chmod(os.path.join(work_dir, info.filename), mode)
    entries = os.listdir(work_dir)
    if len(entries) != 1:
        shutil.rmtree(work_dir, ignore_errors=True)
        die("unexpected zip structure")
    return work_dir, os.path.join(work_dir, entries[0])

def _make_rcfile(repo_dir):
    banner_text = """
      ============================================================
       Library Forge
      ============================================================

       A tiny math library (add.cpp, mul.cpp, mathx.hpp) and an app.cpp
       that calls it. The Makefile has TODO targets you must fill in.
       
       Step 1 -- build and link STATICALLY
         Open the Makefile and fill in the TODOs for the static side:
           1. archive add.o and mul.o into libmathx.a with 'ar rcs'
           2. link app.cpp against libmathx.a to produce app_static
         Then run:
           make app_static
           ./app_static
         It should print two lines and need nothing else at run time.
       
       Step 2 -- build and link DYNAMICALLY
         Fill in the TODOs for the shared side (step 3 below is already
         written for you -- only steps 4 and 5 are TODOs):
           3. (already provided) add.cpp and mul.cpp compiled with -fPIC
           4. link the position-independent objects into libmathx.so
              with -shared
           5. link app.cpp against libmathx.so to produce app_dynamic
         Then run:
           make app_dynamic
           ./app_dynamic
         Watch closely -- this will likely FAIL with an error about
         loading a shared library. That failure is the point: a dynamic
         binary only records the SONAME 'libmathx.so', not a path, and
         the loader does not search the current directory by default.
       
       Step 3 -- fix it with LD_LIBRARY_PATH
         LD_LIBRARY_PATH=. ./app_dynamic
         This time it should print the same two lines as app_static.
       
       Step 4 -- confirm the dependency with ldd
         LD_LIBRARY_PATH=. ldd app_dynamic
         You should see libmathx.so resolved to a path inside this
         directory. Without LD_LIBRARY_PATH, ldd would show it as
         'not found'.
       
       When both app_static and app_dynamic build and run correctly,
       type 'exit'. The launcher rebuilds everything itself and checks
       that the static binary runs with no environment help, that the
       dynamic binary FAILS without LD_LIBRARY_PATH and SUCCEEDS with
       it, and that libmathx.a and libmathx.so both exist.
      ============================================================

    """
    rcfile = tempfile.NamedTemporaryFile(mode="w", suffix=".rc", delete=False)
    rcfile.write(
        f'PS1=\'\\u@library-forge:\\W\\$ \'\n'
        f'cd "{repo_dir}"\n'
        "cat << 'BANNER'\n" + banner_text + "\nBANNER\n"
    )
    rcfile.close()
    return rcfile

def _drop_to_shell(repo_dir):
    rcfile = _make_rcfile(repo_dir)
    shell = os.environ.get("SHELL", "/bin/bash")
    try:
        subprocess.run([shell, "--rcfile", rcfile.name])
    finally:
        try:
            os.remove(rcfile.name)
        except OSError:
            pass

def run_shell_drop_once():
    work_dir, repo_dir = _extract_repo()
    _drop_to_shell(repo_dir)
    return repo_dir, work_dir

def run_shell_drop_with_retry(is_ready, not_ready_lines):
    work_dir, repo_dir = _extract_repo()
    while True:
        _drop_to_shell(repo_dir)
        if is_ready(repo_dir):
            return repo_dir, work_dir
        print()
        for line in not_ready_lines(repo_dir):
            print(line)
        print()
        try:
            again = input("  Try again? [y/n] ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            print()
            shutil.rmtree(work_dir, ignore_errors=True)
            return None, None
        if again != "y":
            shutil.rmtree(work_dir, ignore_errors=True)
            return None, None

def run_shell_drop_validated(check):
    work_dir, repo_dir = _extract_repo()
    try:
        while True:
            _drop_to_shell(repo_dir)
            print()
            _banner("Library Forge -- Checking Your Work")
            print()
            passphrase, feedback = check(repo_dir)
            if passphrase is not None:
                _show_passphrase(passphrase)
                return True
            for line in feedback:
                print(line)
            print()
            try:
                again = input("  Try again? [y/n] ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                print()
                return False
            if again != "y":
                return False
            print()
    finally:
        shutil.rmtree(work_dir, ignore_errors=True)

class ActivityEngine:
    """Core build/run/validate logic for Library Forge; importable without a TTY."""

    slug = "library-forge"
    title = "Library Forge"
    description = 'Build a tiny math library both ways -- as a static archive (libmathx.a) and as a shared object (libmathx.so) -- link an app against each, and see the loader error that dynamic linking can produce when LD_LIBRARY_PATH is not set. The launcher rebuilds your Makefile targets and checks both binaries itself.'

    def _run_env(self, repo_dir, name, env_extra):
        exe = os.path.join(repo_dir, name)
        if not os.path.isfile(exe):
            return None, None, f"{name} binary not found"
        env = dict(os.environ)
        env.pop("LD_LIBRARY_PATH", None)
        env.update(env_extra)
        try:
            r = subprocess.run([exe], capture_output=True, text=True, timeout=10,
                               cwd=repo_dir, env=env)
        except subprocess.TimeoutExpired:
            return None, None, "timeout"
        return r.returncode, r.stdout.strip(), r.stderr.strip()

    def _check(self, repo_dir):
        build_ok, build_err = _make_build(repo_dir)
        if not build_ok:
            lines = ["  make failed.  Fix the Makefile TODOs first."]
            lines += [f"    {ln}" for ln in build_err.strip().splitlines()[:12]]
            return None, lines

        static_lib = os.path.join(repo_dir, "libmathx.a")
        shared_lib = os.path.join(repo_dir, "libmathx.so")
        missing = [p for p in (static_lib, shared_lib) if not os.path.isfile(p)]
        if missing:
            names = ", ".join(os.path.basename(p) for p in missing)
            return None, [f"  Missing after build: {names}",
                           "  Check the corresponding Makefile TODO(s)."]

        rc, out, err = self._run_env(repo_dir, "app_static", {})
        if rc != 0 or out is None:
            return None, [
                "  app_static did not run cleanly with no LD_LIBRARY_PATH set.",
                "  A statically-linked binary should never need it.",
                f"  exit code: {rc}", f"  stderr: {err}",
            ]

        rc_bad, out_bad, err_bad = self._run_env(repo_dir, "app_dynamic", {})
        if rc_bad == 0:
            return None, [
                "  app_dynamic ran successfully WITHOUT LD_LIBRARY_PATH set.",
                "  That should not happen -- the loader should fail to find",
                "  libmathx.so unless the current directory is on its search",
                "  path.  Did you accidentally link app_dynamic statically?",
            ]

        rc_ok, out_ok, err_ok = self._run_env(repo_dir, "app_dynamic", {"LD_LIBRARY_PATH": repo_dir})
        if rc_ok != 0 or out_ok is None:
            return None, [
                "  app_dynamic still failed to run even WITH",
                "  LD_LIBRARY_PATH set to the repo directory.",
                f"  exit code: {rc_ok}", f"  stderr: {err_ok}",
            ]

        try:
            ldd_env = dict(os.environ)
            ldd_env["LD_LIBRARY_PATH"] = repo_dir
            ldd = subprocess.run(["ldd", os.path.join(repo_dir, "app_dynamic")],
                                 capture_output=True, text=True, timeout=10, env=ldd_env)
        except (FileNotFoundError, subprocess.TimeoutExpired):
            ldd = None
        if ldd is None or "libmathx.so" not in ldd.stdout or "not found" in ldd.stdout:
            lines = ["  ldd did not show libmathx.so as a resolved dependency",
                     "  of app_dynamic.  Is app_dynamic really linked dynamically?"]
            if ldd is not None:
                lines += [f"    {ln}" for ln in ldd.stdout.splitlines()]
            return None, lines

        if out != out_ok:
            return None, [
                "  app_static and app_dynamic printed different output.",
                f"  static:  {out!r}", f"  dynamic: {out_ok!r}",
                "  Both binaries should print the same two lines.",
            ]

        passphrase = _decrypt(out)
        if passphrase is not None:
            return passphrase, []
        return None, [
            "  Everything built and linked correctly, but the program's",
            "  own output did not match what is expected.  Did you change",
            "  mx_add, mx_mul, or the printf lines in app.cpp?",
            "",
            "  Your output was:",
        ] + [f"    {ln}" for ln in out.splitlines()]


    def check(self, repo_dir):
        """Build+run the student's repo; return (passphrase_or_None, feedback_lines)."""
        return self._check(repo_dir)


ENGINE = ActivityEngine()


def main():
    _banner(ENGINE.title)
    print()
    input("  Press Enter to begin...")

    ok = run_shell_drop_validated(ENGINE.check)
    if not ok:
        sys.exit(0)


if __name__ == "__main__":
    main()
